c
// Michael-Scott Lock-Free Enqueue
void enqueue(Queue* q, int val) {
Node* n = new Node(val);
while (true) {
Node* tail = q->tail;
Node* next = tail->next;
if (tail == q->tail) { // Consistency check
if (next == NULL) {
// --- PHASE 1: Try to link new node ---
if (CAS(&tail->next, NULL, n)) {
// --- PHASE 2: Try to advance tail ---
CAS(&q->tail, tail, n);
return;
}
} else {
// --- HELPING: Tail lagging, advance it ---
CAS(&q->tail, tail, next);
}
}
}
}
